**2. Jacobian + 阻尼最小二乘 IK**

```cpp
#include <Eigen/Dense>
#include <Eigen/SVD>
#include <iostream>

Eigen::MatrixXd compute_jacobian(
    const std::vector<DHParams>& dh,
    const Eigen::VectorXd& q, double delta = 1e-6) {
    int n = q.size();
    Eigen::Matrix4d T0 = forward_kinematics(dh, q);
    Eigen::MatrixXd J(6, n);

    for (int i = 0; i < n; ++i) {
        Eigen::VectorXd q_perturbed = q;
        q_perturbed(i) += delta;
        Eigen::Matrix4d Ti = forward_kinematics(dh, q_perturbed);
        // 位置 Jacobian (数值差分)
        J.block<3,1>(0,i) = (Ti.block<3,1>(0,3) - T0.block<3,1>(0,3)) / delta;
        // 姿态 Jacobian (简化: 用旋转矩阵差分)
        Eigen::Matrix3d dR = Ti.block<3,3>(0,0) * T0.block<3,3>(0,0).transpose();
        Eigen::AngleAxisd aa(dR);
        J.block<3,1>(3,i) = aa.axis() * aa.angle() / delta;
    }
    return J;
}

Eigen::VectorXd damped_least_squares_ik(
    const std::vector<DHParams>& dh,
    const Eigen::Matrix4d& target,
    Eigen::VectorXd q_init,
    int max_iter = 100, double tol = 1e-4, double lambda = 0.01) {

    Eigen::VectorXd q = q_init;
    for (int iter = 0; iter < max_iter; ++iter) {
        Eigen::Matrix4d T = forward_kinematics(dh, q);

        // 位置误差
        Eigen::VectorXd error(6);
        error.head<3>() = target.block<3,1>(0,3) - T.block<3,1>(0,3);
        // 姿态误差
        Eigen::Matrix3d Re = target.block<3,3>(0,0) * T.block<3,3>(0,0).transpose();
        Eigen::AngleAxisd aa(Re);
        error.tail<3>() = aa.axis() * aa.angle();

        if (error.norm() < tol) break;

        Eigen::MatrixXd J = compute_jacobian(dh, q);
        // 阻尼最小二乘: dq = J^T (JJ^T + λI)^{-1} e
        Eigen::MatrixXd JJt = J * J.transpose();
        JJt += lambda * lambda * Eigen::MatrixXd::Identity(6,6);
        Eigen::VectorXd dq = J.transpose() * JJt.ldlt().solve(error);
        q += dq;
    }
    return q;
}
```

**3. Eigen vs 手写循环性能对比**

```cpp
#include <Eigen/Dense>
#include <chrono>
#include <iostream>

void benchmark_matmul(int size = 100, int iterations = 1000) {
    Eigen::MatrixXd A = Eigen::MatrixXd::Random(size, size);
    Eigen::MatrixXd B = Eigen::MatrixXd::Random(size, size);
    Eigen::MatrixXd C(size, size);

    // Eigen 矩阵乘法
    auto t0 = std::chrono::high_resolution_clock::now();
    for (int i = 0; i < iterations; ++i) {
        C.noalias() = A * B;  // noalias 避免临时矩阵
    }
    auto t1 = std::chrono::high_resolution_clock::now();
    double eigen_ms = std::chrono::duration<double, std::milli>(t1-t0).count();

    // 手写循环
    t0 = std::chrono::high_resolution_clock::now();
    for (int iter = 0; iter < iterations; ++iter) {
        for (int i = 0; i < size; ++i)
            for (int j = 0; j < size; ++j) {
                C(i,j) = 0;
                for (int k = 0; k < size; ++k)
                    C(i,j) += A(i,k) * B(k,j);
            }
    }
    t1 = std::chrono::high_resolution_clock::now();
    double naive_ms = std::chrono::duration<double, std::milli>(t1-t0).count();

    std::cout << "Matrix " << size << "x" << size 
              << " x" << iterations << ":\n";
    std::cout << "  Eigen:  " << eigen_ms << " ms\n";
    std::cout << "  Naive:  " << naive_ms << " ms\n";
    std::cout << "  Speedup: " << naive_ms/eigen_ms << "x\n";
    // 典型结果: Eigen 快 10-50x (利用 SIMD + cache 优化)
}
```
